class Playground {
    async run(inputs) {
        // Setup
        const inputStr = inputs[0] || '10, 20, 30, 40';
        const vals = inputStr.split(',').map(s => s.trim());

        this.log('Initializing list...');
        this.list.init(vals);
        await this.await();

        // Initialize pointers
        this.log('Initializing pointers: prev = NULL, curr = HEAD');
        let prev = null;
        let curr = this.list.pointers['head']; // Get ID of head node

        this.list.createPointer('prev', null);
        this.list.createPointer('curr', curr);
        await this.await();

        while (curr) {
            // 1. Save next
            this.log('Save next: temp = curr.next');
            const nextNodeId = this.list.getNextId(curr);
            let temp = nextNodeId;
            this.list.createPointer('temp', temp);
            await this.await();

            // 2. Reverse link
            this.log('Reverse link: curr.next = prev');
            this.list.link(curr, prev);
            // Note: link(from, to) updates the visual link.
            // If prev is null, it removes the link (sets next to null).
            if (!prev) this.list.unlink(curr);
            else this.list.link(curr, prev);

            await this.await();

            // 3. Move prev
            this.log('Move prev: prev = curr');
            prev = curr;
            this.list.movePointer('prev', prev);
            await this.await();

            // 4. Move curr
            this.log('Move curr: curr = temp');
            curr = temp;
            this.list.movePointer('curr', curr);
            await this.await();

            // Cleanup temp
            this.list.removePointer('temp');
        }

        // Finalize
        this.log('Update Head: head = prev');
        this.list.pointers['head'] = prev;
        this.list.render();
        await this.await();

        this.log('Done.');
    }
}
